const jwt = require('jsonwebtoken');
const fs = require('fs');

// SECURE: Load signing key/secret from secure storage
const JWT_SECRET = process.env.JWT_SECRET; // For HS256
const publicKey = fs.readFileSync('./keys/jwt-public.pem', 'utf8'); // For RS256

// ❌ VULNERABLE: No algorithm specified
function vulnerableVerify(token) {
  return jwt.verify(token, JWT_SECRET); // Accepts any algorithm!
}

// ✅ SECURE: Explicit algorithm allowlisting for HS256
function secureVerifyHS256(token) {
  return jwt.verify(token, JWT_SECRET, {
    algorithms: ['HS256'], // Only accepts HS256
    issuer: 'https://yourdomain.com',
    audience: 'https://api.yourdomain.com'
  });
}

// ✅ SECURE: Explicit algorithm allowlisting for RS256
function secureVerifyRS256(token) {
  return jwt.verify(token, publicKey, {
    algorithms: ['RS256'], // Only accepts RS256
    issuer: 'https://yourdomain.com',
    audience: 'https://api.yourdomain.com'
  });
}

// ✅ SECURE: Express middleware with algorithm enforcement
const expressJWT = require('express-jwt');

const authMiddleware = expressJWT({
  secret: JWT_SECRET,
  algorithms: ['HS256'], // Critical: Blocks 'none' and RS256
  issuer: 'https://yourdomain.com',
  audience: 'https://api.yourdomain.com',
  credentialsRequired: true,
  getToken: (req) => {
    if (req.headers.authorization?.startsWith('Bearer ')) {
      return req.headers.authorization.substring(7);
    }
    return null;
  }
});

app.use('/api/protected', authMiddleware);

// Error handling for JWT verification failures
app.use((err, req, res, next) => {
  if (err.name === 'UnauthorizedError') {
    return res.status(401).json({
      error: 'Invalid token',
      message: err.message
    });
  }
  next(err);
});

