import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import io.jsonwebtoken.security.SignatureException;
import javax.crypto.SecretKey;
import java.security.Key;
import java.nio.charset.StandardCharsets;

public class JWTService {

    private final SecretKey secretKey;
    private final String issuer = "https://yourdomain.com";
    private final String audience = "https://api.yourdomain.com";

    public JWTService(String secret) {
        // Ensure secret is strong enough (minimum 256 bits for HS256)
        this.secretKey = Keys.hmacShaKeyFor(secret.getBytes(StandardCharsets.UTF_8));
    }

    // ❌ VULNERABLE: No algorithm specified
    public Claims vulnerableParseToken(String token) {
        return Jwts.parserBuilder()
            .setSigningKey(secretKey)
            .build()
            .parseClaimsJws(token)
            .getBody(); // Accepts any algorithm!
    }

    // ✅ SECURE: Explicit algorithm allowlisting
    public Claims secureParseToken(String token) {
        try {
            JwtParser parser = Jwts.parserBuilder()
                .setSigningKey(secretKey)
                .requireIssuer(issuer)
                .requireAudience(audience)
                // CRITICAL: Only accept HS256
                .setSigningKeyResolver(new SigningKeyResolverAdapter() {
                    @Override
                    public Key resolveSigningKey(JwsHeader header, Claims claims) {
                        // Validate algorithm before verification
                        String alg = header.getAlgorithm();
                        if (!"HS256".equals(alg)) {
                            throw new JwtException(
                                "Invalid algorithm. Expected HS256, got: " + alg
                            );
                        }
                        return secretKey;
                    }
                })
                .build();

            return parser.parseClaimsJws(token).getBody();

        } catch (SignatureException e) {
            throw new JwtException("Invalid signature", e);
        } catch (ExpiredJwtException e) {
            throw new JwtException("Token expired", e);
        } catch (JwtException e) {
            throw new JwtException("Invalid token: " + e.getMessage(), e);
        }
    }

    // ✅ SECURE: Spring Security configuration
    @Bean
    public JwtDecoder jwtDecoder() {
        SecretKeySpec secretKeySpec = new SecretKeySpec(
            secretKey.getEncoded(),
            SignatureAlgorithm.HS256.getJcaName()
        );

        NimbusJwtDecoder decoder = NimbusJwtDecoder
            .withSecretKey(secretKeySpec)
            .macAlgorithm(MacAlgorithm.HS256) // Enforces HS256 only
            .build();

        // Additional validation
        decoder.setJwtValidator(JwtValidators.createDefaultWithIssuer(issuer));

        return decoder;
    }
}

