const jwt = require('jsonwebtoken');
const axios = require('axios');
const NodeCache = require('node-cache');

// Cache for JWKS (JSON Web Key Set) - refresh every 10 minutes
const jwksCache = new NodeCache({ stdTTL: 600, checkperiod: 120 });

// ✅ SECURE: Retrieve public keys from trusted JWKS endpoint
async function getPublicKey(kid) {
  // Check cache first
  const cached = jwksCache.get(kid);
  if (cached) return cached;

  try {
    // Fetch from trusted JWKS endpoint (your own auth server)
    const jwksUrl = 'https://auth.yourdomain.com/.well-known/jwks.json';
    const response = await axios.get(jwksUrl, { timeout: 5000 });

    const key = response.data.keys.find(k => k.kid === kid);
    if (!key) {
      throw new Error(`No key found for kid: ${kid}`);
    }

    // Convert JWK to PEM format for verification
    const jwkToPem = require('jwk-to-pem');
    const publicKey = jwkToPem(key);

    // Cache the key
    jwksCache.set(kid, publicKey);
    return publicKey;

  } catch (error) {
    console.error('Failed to fetch JWKS:', error);
    throw new Error('Unable to verify token signature');
  }
}

// ❌ VULNERABLE: Uses key from JWT header (CVE-2018-0114 style attack)
function vulnerableVerifyWithJWK(token) {
  const decoded = jwt.decode(token, { complete: true });

  // DANGER: Trusting key from untrusted token!
  if (decoded.header.jwk) {
    const jwkToPem = require('jwk-to-pem');
    const publicKey = jwkToPem(decoded.header.jwk);
    return jwt.verify(token, publicKey, { algorithms: ['RS256'] });
  }
}

// ✅ SECURE: Key pinning with algorithm validation
async function secureVerifyWithKeyPinning(token) {
  try {
    // Decode header without verification to get kid
    const decoded = jwt.decode(token, { complete: true });

    if (!decoded) {
      throw new Error('Invalid token format');
    }

    // Validate algorithm before fetching key
    const alg = decoded.header.alg;
    const allowedAlgorithms = ['RS256', 'ES256'];

    if (!allowedAlgorithms.includes(alg)) {
      throw new Error(`Unsupported algorithm: ${alg}`);
    }

    // Ensure 'none' algorithm is explicitly rejected
    if (alg === 'none' || alg === 'None' || alg === 'NONE') {
      throw new Error('Algorithm "none" is not allowed');
    }

    // Get kid from header
    const kid = decoded.header.kid;
    if (!kid) {
      throw new Error('Missing key ID (kid) in token header');
    }

    // Fetch trusted public key from JWKS endpoint
    const publicKey = await getPublicKey(kid);

    // Verify with strict options
    const verified = jwt.verify(token, publicKey, {
      algorithms: [alg], // Use the algorithm from header (already validated)
      issuer: 'https://yourdomain.com',
      audience: 'https://api.yourdomain.com',
      clockTolerance: 30, // Allow 30 seconds clock skew
      maxAge: '1h' // Reject tokens older than 1 hour
    });

    return verified;

  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      throw new Error('Token has expired');
    } else if (error.name === 'JsonWebTokenError') {
      throw new Error('Token signature verification failed');
    }
    throw error;
  }
}

// ✅ SECURE: Express middleware with key pinning
function authMiddleware(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'No token provided' });
  }

  const token = authHeader.substring(7);

  secureVerifyWithKeyPinning(token)
    .then(decoded => {
      req.user = decoded;
      next();
    })
    .catch(error => {
      console.error('JWT verification failed:', error.message);
      return res.status(403).json({ 
        error: 'Invalid token',
        message: error.message 
      });
    });
}

app.use('/api/protected', authMiddleware);

const jwt = require('jsonwebtoken'); // Use latest version (^9.0.0+)
const crypto = require('crypto');

// ✅ SECURE: Comprehensive JWT validation configuration
class SecureJWTService {
  constructor(config) {
    this.config = {
      secret: config.secret,
      issuer: config.issuer || 'https://yourdomain.com',
      audience: config.audience || 'https://api.yourdomain.com',
      algorithm: config.algorithm || 'HS256',
      expiresIn: config.expiresIn || '1h',
      notBefore: config.notBefore || '0s',
      // Additional security options
      validateClaims: true,
      enforceJti: true, // Require unique token ID
      revokedTokensStore: new Set() // In production, use Redis
    };

    // Validate algorithm on initialization
    const allowedAlgorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'ES256'];
    if (!allowedAlgorithms.includes(this.config.algorithm)) {
      throw new Error(`Unsupported algorithm: ${this.config.algorithm}`);
    }
  }

  // Generate token with security best practices
  generateToken(payload) {
    // Generate unique token ID (jti) for token revocation tracking
    const jti = crypto.randomBytes(16).toString('hex');

    // Add security claims
    const securePayload = {
      ...payload,
      jti: jti,
      iat: Math.floor(Date.now() / 1000),
      // Optional: Add IP binding
      // ip: payload.clientIp,
      // Optional: Add session fingerprint
      // fingerprint: this.generateFingerprint(payload.userAgent, payload.clientIp)
    };

    const token = jwt.sign(securePayload, this.config.secret, {
      algorithm: this.config.algorithm,
      expiresIn: this.config.expiresIn,
      notBefore: this.config.notBefore,
      issuer: this.config.issuer,
      audience: this.config.audience,
      jwtid: jti
    });

    return { token, jti };
  }

  // Verify token with defense-in-depth validation
  verifyToken(token, options = {}) {
    try {
      // First: Decode without verification to check structure
      const decoded = jwt.decode(token, { complete: true });

      if (!decoded) {
        throw new Error('Invalid token format');
      }

      // Validate algorithm before verification (defense-in-depth)
      if (decoded.header.alg !== this.config.algorithm) {
        throw new Error(
          `Algorithm mismatch. Expected ${this.config.algorithm}, got ${decoded.header.alg}`
        );
      }

      // Explicitly block 'none' algorithm variations
      const alg = decoded.header.alg;
      if (/^none$/i.test(alg)) {
        throw new Error('Algorithm "none" is explicitly forbidden');
      }

      // Check token revocation (if jti present)
      if (this.config.enforceJti && decoded.payload.jti) {
        if (this.config.revokedTokensStore.has(decoded.payload.jti)) {
          throw new Error('Token has been revoked');
        }
      }

      // Now perform cryptographic verification
      const verified = jwt.verify(token, this.config.secret, {
        algorithms: [this.config.algorithm], // CRITICAL: Algorithm allowlist
        issuer: this.config.issuer,
        audience: this.config.audience,
        clockTolerance: 30,
        maxAge: this.config.expiresIn,
        complete: true // Get full token object
      });

      // Additional custom validations
      if (this.config.validateClaims) {
        this.validateCustomClaims(verified.payload, options);
      }

      return verified.payload;

    } catch (error) {
      // Log security events
      this.logSecurityEvent('token_verification_failed', {
        error: error.message,
        tokenPreview: token.substring(0, 20) + '...'
      });

      throw error;
    }
  }

  // Custom claim validation
  validateCustomClaims(payload, options) {
    // Validate required claims exist
    const requiredClaims = ['sub', 'iat', 'exp'];
    for (const claim of requiredClaims) {
      if (!payload[claim]) {
        throw new Error(`Missing required claim: ${claim}`);
      }
    }

    // Validate user ID format
    if (payload.sub && !/^[a-zA-Z0-9-]{1,36}$/.test(payload.sub)) {
      throw new Error('Invalid user ID format');
    }

    // Optional: IP binding validation
    if (options.clientIp && payload.ip) {
      if (payload.ip !== options.clientIp) {
        throw new Error('Token IP mismatch - possible token theft');
      }
    }

    // Validate token age is reasonable (not too old)
    const tokenAge = Date.now() / 1000 - payload.iat;
    if (tokenAge > 86400) { // 24 hours
      throw new Error('Token too old');
    }
  }

  // Revoke token by JTI
  revokeToken(jti) {
    this.config.revokedTokensStore.add(jti);
    // In production: Store in Redis with expiration
    this.logSecurityEvent('token_revoked', { jti });
  }

  // Security event logging
  logSecurityEvent(event, data) {
    console.log(JSON.stringify({
      timestamp: new Date().toISOString(),
      event: event,
      severity: 'warning',
      ...data
    }));
  }
}

// ✅ Usage example
const jwtService = new SecureJWTService({
  secret: process.env.JWT_SECRET,
  issuer: 'https://yourdomain.com',
  audience: 'https://api.yourdomain.com',
  algorithm: 'HS256',
  expiresIn: '1h'
});

// Express middleware
function authMiddleware(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    const decoded = jwtService.verifyToken(token, {
      clientIp: req.ip // Optional IP binding
    });

    req.user = decoded;
    next();

  } catch (error) {
    return res.status(403).json({ 
      error: 'Invalid token',
      message: error.message 
    });
  }
}

app.use('/api/protected', authMiddleware);

// Logout endpoint (token revocation)
app.post('/api/logout', authMiddleware, (req, res) => {
  if (req.user.jti) {
    jwtService.revokeToken(req.user.jti);
  }
  res.json({ message: 'Logged out successfully' });
});
